#[derive(Clone, Copy, Debug, Eq, Ord, PartialEq, PartialOrd)]
pub enum SudEventKind {
    Exec,
    Argv,
    Env,
    Open,
    Cwd,
    Stdout,
    Stderr,
    Exit,
    Prof,
}

impl WireValue for SudEventKind {
    fn encode_atom(&self, output: &mut Vec<u8>) -> Result<(), DecodeError> {
        let code = match self {
            Self::Exec => 1,
            Self::Argv => 2,
            Self::Env => 3,
            Self::Open => 4,
            Self::Cwd => 5,
            Self::Stdout => 6,
            Self::Stderr => 7,
            Self::Exit => 8,
            Self::Prof => 9,
        };
        put_u64(output, code);
        Ok(())
    }

    fn decode_atom(input: &mut &[u8]) -> Result<Self, DecodeError> {
        match get_u64(input)? {
            1 => Ok(Self::Exec),
            2 => Ok(Self::Argv),
            3 => Ok(Self::Env),
            4 => Ok(Self::Open),
            5 => Ok(Self::Cwd),
            6 => Ok(Self::Stdout),
            7 => Ok(Self::Stderr),
            8 => Ok(Self::Exit),
            9 => Ok(Self::Prof),
            _ => Err(DecodeError::InvalidValue),
        }
    }
}

